<?php$years = $_GET['years'];$months = $_GET['months'];$days = $_GET['days'];$prevs = $_GET['prevs'];$nexts = $_GET['nexts'];if($prevs == 1){    $monthsTemp = $months - 1;    $months = $monthsTemp;    if($months < 1){        $years = $years - 1;        $months = 12;    }}if($nexts == 1){    $monthsTemp = $months + 1;    $months = $monthsTemp;    if($months > 12){        $years = $years + 1;        $months = 1;    }}if($years != ""){ $nowData_Year = $years; }else{ $nowData_Year = date("Y"); } // 현재 날짜 년if($months != ""){ $nowData_Month = $months; }else{ $nowData_Month = date("m"); } // 현재 날짜 월if($days != ""){ $nowData_day = $days; }else{ $nowData_day = date("d"); } // 현재 날짜 일// -- 각 날짜 변수 -- //$cal_year=$nowData_Year;$cal_month=$nowData_Month;$cal_day=$nowData_day;$cal_Sum_str1 = $cal_year."-".$cal_month."-".$cal_day;$dateFirstTime = $cal_year."-".$cal_month."-01";// ---- 그달의 마지막 날짜를 구한다 ----------- //$check_28=checkdate($cal_month, 28, $cal_year);$check_29=checkdate($cal_month, 29, $cal_year);$check_30=checkdate($cal_month, 30, $cal_year);$check_31=checkdate($cal_month, 31, $cal_year);if($check_28 != "") $last_day=28;if($check_29 != "") $last_day=29;if($check_30 != "") $last_day=30;if($check_31 != "") $last_day=31;$yoil = array("일","월","화","수","목","금","토");$check_1_get_week = ($yoil[date('w', strtotime($dateFirstTime))]); // 현재 요일날짜if($check_1_get_week == "일"){ $j_temp_change_num = 0; }if($check_1_get_week == "월"){ $j_temp_change_num = 1; }if($check_1_get_week == "화"){ $j_temp_change_num = 2; }if($check_1_get_week == "수"){ $j_temp_change_num = 3; }if($check_1_get_week == "목"){ $j_temp_change_num = 4; }if($check_1_get_week == "금"){ $j_temp_change_num = 5; }if($check_1_get_week == "토"){ $j_temp_change_num = 6; }$yoil = array("일","월","화","수","목","금","토");$yoilResult = ($yoil[date('w', strtotime($cal_year."-".$cal_month."-".$cal_day))]); // 현재 요일날짜$nowData_Month_ch = $nowData_Month;$nowData_Month_ch_strlen = strlen($nowData_Month_ch);if($nowData_Month_ch_strlen > 1){ // 월이 1글자 이상이면    if($nowData_Month_ch[0] == 0){        $nowData_Month_ch = $nowData_Month_ch[1];    }}$nowData_Month_ch_prev = $nowData_Month_ch - 1;$nowData_Month_ch_next = $nowData_Month_ch + 1;if($nowData_Month_ch <= 1){    $nowData_Month_ch_prev = 12;}if($nowData_Month_ch >= 12) {    $nowData_Month_ch_next = 1;}?><script>    var ca_sc_add_temp_save1 = "";    var ca_sc_add_temp_save2 = "";    var ca_sc_add_temp_save3 = "";    function ca_sc_add_temp_saveF(str1,str2,str3){        ca_sc_add_temp_save1 = str1;        ca_sc_add_temp_save2 = str2;        ca_sc_add_temp_save3 = str3;        // console.log(ca_sc_add_temp_save1);        // console.log(ca_sc_add_temp_save2);        // console.log(ca_sc_add_temp_save3);        dddd = ca_sc_add_temp_save1+"-"+ca_sc_add_temp_save2+"-"+ca_sc_add_temp_save3;        $("#date_area").val(dddd);    }</script><div class="pop datepop <?php if($prevs == 1 or $nexts == 1){ echo "on"; } ?> " id="pop_datepop_area" >    <div class="black_bg"></div>    <div class="white_bg">        <h2 class="p_h2">            <span class="vt_mid">일정변경</span>        </h2>        <div class="set7 s7cal">            <div class="calendar">                <div class="cal_top">                    <div class="ct1 vt_mid"><?=$nowData_Year?></div>                    <div class="ct2 vt_mid">                        <button type="button" class="prev d_btns" onClick = "location.href = './set7_add.php?years=<?=$nowData_Year?>&months=<?=$nowData_Month?>&days=<?=$nowData_day?>&prevs=1'"><?=$nowData_Month_ch_prev?>월</button>                        <span class="mg"><?=$nowData_Month_ch?>월</span>                        <button type="button" class="next d_btns" onClick = "location.href = './set7_add.php?years=<?=$nowData_Year?>&months=<?=$nowData_Month?>&days=<?=$nowData_day?>&nexts=1